#include<bits/stdc++.h>
using namespace std;
int n,x,h[100010];
bool check(int mid)
{
    for(int i=mid;i<n;i++)
    {
        if(h[i]-h[i-mid]<x*2)
        {
            return false;
        }
    }
    return true;
}
int main()
{
    scanf("%d%d",&n,&x);
    for(int i=1;i<n;i++)
    {
        scanf("%d",&h[i]);
        h[i]+=h[i-1];
    }
    int l=0,r=1e9,best;
    while(l<=r)
    {
        int mid=(l+r)/2;
        if(check(mid))
        {
            r=mid-1;
            best=mid;
        }
        else
        {
            l=mid+1;
        }
    }
    printf("%d",best);
    return 0;
}
